def _py2gb_cli_module_available ():
	"""Return True when at least one py2gb/py2gba CLI module is importable."""
	for mod in ('py2gb.__main__', 'py2gba.__main__'):
		try:
			__import__(mod)
			return True
		except Exception:
			continue
	return False
