def GetScripts (ob):
	scripts = []
	for i in range(MAX_SCRIPTS_PER_OBJECT):
		if not getattr(ob, 'scriptDisable%i' %i):
			txt = getattr(ob, 'script%i' %i)
			if txt:
				scripts.append((txt.as_string(), getattr(ob, 'initScript%i' %i), getattr(ob, 'scriptType%i' %i), txt, getattr(ob, 'scriptIsGlobal%i' %i, False)))
	return scripts

def _js13k_script_type_js_prefix (script_type):
	'''One-line JS so each injected init/update block sees SCRIPT_TYPE (matches SCRIPT_TYPE_ITEMS ids).'''
	try:
		return 'var SCRIPT_TYPE = ' + json.dumps(str(script_type)) + ';\n'
	except Exception:
		return 'var SCRIPT_TYPE = "";\n'

def _js13k_script_type_py_prefix (script_type):
	'''One-line Python prepended to transpile / mirror / Codon sources.'''
	try:
		return 'SCRIPT_TYPE = ' + repr(str(script_type)) + '\n'
	except Exception:
		return 'SCRIPT_TYPE = ""\n'

_GB_GLOBAL_MEMBER_NODE_TYPES = (
	ast.Import,
	ast.ImportFrom,
	ast.Assign,
	ast.AnnAssign,
	ast.FunctionDef,
	ast.AsyncFunctionDef,
	ast.ClassDef,
)

def _get_ast_node_source_segment (code : str, lines : list, node):
	segment = ast.get_source_segment(code, node)
	if segment is None:
		start = getattr(node, 'lineno', None)
		end = getattr(node, 'end_lineno', None)
		if isinstance(start, int) and isinstance(end, int) and start >= 1 and end >= start:
			segment = '\n'.join(lines[start - 1 : end])
	return segment

def _build_gbc_global_assign_prefix (code : str, lines : list, node):
	'''Build one-time initializer source for simple top-level gbc globals.'''
	target_name = None
	value_node = None
	if isinstance(node, ast.Assign):
		if len(node.targets) == 1 and isinstance(node.targets[0], ast.Name):
			target_name = node.targets[0].id
			value_node = node.value
	elif isinstance(node, ast.AnnAssign):
		if isinstance(node.target, ast.Name):
			target_name = node.target.id
			value_node = node.value
	if not isinstance(target_name, str) or target_name == '':
		return None
	if not isinstance(value_node, ast.AST):
		return 'global ' + target_name
	value_segment = _get_ast_node_source_segment(code, lines, value_node)
	if not isinstance(value_segment, str) or value_segment.strip() == '':
		return None
	return (
		'global ' + target_name + '\n'
		+ '_js13k_gbc_global_values = globals().get("_js13k_gbc_global_values", None)\n'
		+ 'if not isinstance(_js13k_gbc_global_values, dict):\n'
		+ '\t_js13k_gbc_global_values = {}\n'
		+ '\tglobals()["_js13k_gbc_global_values"] = _js13k_gbc_global_values\n'
		+ '_js13k_gbc_global_init_done = globals().get("_js13k_gbc_global_init_done", None)\n'
		+ 'if not isinstance(_js13k_gbc_global_init_done, set):\n'
		+ '\t_js13k_gbc_global_init_done = set()\n'
		+ '\tglobals()["_js13k_gbc_global_init_done"] = _js13k_gbc_global_init_done\n'
		+ 'if "' + target_name + '" not in _js13k_gbc_global_init_done:\n'
		+ '\t' + target_name + ' = ' + value_segment.strip() + '\n'
		+ '\t_js13k_gbc_global_init_done.add("' + target_name + '")'
		+ '\nelse:\n'
		+ '\tif "' + target_name + '" not in globals():\n'
		+ '\t\t' + target_name + ' = _js13k_gbc_global_values.get("' + target_name + '", ' + value_segment.strip() + ')\n'
		+ '_js13k_gbc_global_values["' + target_name + '"] = ' + target_name
	)

def _extract_top_level_member_defs (code : str):
	'''Return source text for top-level member definitions in a script.'''
	try:
		tree = ast.parse(code)
	except Exception:
		return ''
	lines = code.splitlines()
	chunks = []
	for node in list(getattr(tree, 'body', []) or []):
		if not isinstance(node, _GB_GLOBAL_MEMBER_NODE_TYPES):
			continue
		segment = None
		if isinstance(node, (ast.Assign, ast.AnnAssign)):
			segment = _build_gbc_global_assign_prefix(code, lines, node)
		if segment is None:
			segment = _get_ast_node_source_segment(code, lines, node)
		if isinstance(segment, str) and segment.strip() != '':
			chunks.append(segment.strip('\n'))
	return '\n\n'.join(chunks)

def _build_gbc_global_members_prefix (script_entries : list):
	'''Build a reusable gbc-py source prefix from scripts marked as global.'''
	parts = []
	for entry in list(script_entries or []):
		if not bool(entry.get('is_global')):
			continue
		raw_code = str(entry.get('raw_code', entry.get('code', '')) or '')
		members = _extract_top_level_member_defs(raw_code)
		if members.strip() != '':
			parts.append(members.strip())
	if not parts:
		return ''
	return '\n\n'.join(parts).strip() + '\n'

def _collect_top_level_assigned_names (code : str):
	'''Collect top-level assigned variable names from gbc-py source.'''
	names = set()
	try:
		tree = ast.parse(code or '')
	except Exception:
		return names
	for node in list(getattr(tree, 'body', []) or []):
		if isinstance(node, ast.Assign):
			for target in list(node.targets or []):
				if isinstance(target, ast.Name) and isinstance(target.id, str):
					names.add(target.id)
		elif isinstance(node, ast.AnnAssign):
			if isinstance(node.target, ast.Name) and isinstance(node.target.id, str):
				names.add(node.target.id)
		elif isinstance(node, ast.AugAssign):
			if isinstance(node.target, ast.Name) and isinstance(node.target.id, str):
				names.add(node.target.id)
	return names

def _collect_gbc_global_member_names (script_entries : list):
	'''Return variable names defined by scripts marked as global.'''
	names = set()
	for entry in list(script_entries or []):
		if not bool(entry.get('is_global')):
			continue
		raw_code = str(entry.get('raw_code', entry.get('code', '')) or '')
		for name in _collect_top_level_assigned_names(raw_code):
			if isinstance(name, str) and re.fullmatch(r'[A-Za-z_]\w*', name) and not name.startswith('__'):
				names.add(name)
	return names

def _inject_global_decls_for_mutated_names (code : str, candidate_names):
	'''Insert global prelude/sync so mutated globals persist safely.'''
	try:
		candidate_set = {str(n) for n in list(candidate_names or []) if isinstance(n, str)}
	except Exception:
		candidate_set = set()
	if not candidate_set:
		return str(code or ''), 0
	code_txt = str(code or '')
	try:
		tree = ast.parse(code_txt)
	except Exception:
		return code_txt, 0
	existing_global_names = set()
	for node in ast.walk(tree):
		if isinstance(node, ast.Global):
			for n in list(node.names or []):
				if isinstance(n, str):
					existing_global_names.add(n)
	mutated = set()
	for node in ast.walk(tree):
		target = None
		if isinstance(node, ast.Assign):
			for t in list(node.targets or []):
				if isinstance(t, ast.Name):
					mutated.add(t.id)
		elif isinstance(node, ast.AnnAssign):
			target = node.target
		elif isinstance(node, ast.AugAssign):
			target = node.target
		if isinstance(target, ast.Name):
			mutated.add(target.id)
	to_add = sorted([
		n for n in list(mutated & candidate_set)
		if isinstance(n, str) and re.fullmatch(r'[A-Za-z_]\w*', n) and n not in existing_global_names
	])
	sync_names = sorted([
		n for n in list(mutated & candidate_set)
		if isinstance(n, str) and re.fullmatch(r'[A-Za-z_]\w*', n)
	])
	if (not to_add) and (not sync_names):
		return code_txt, 0
	prelude_lines = []
	if to_add:
		prelude_lines.append('global ' + ', '.join(to_add))
	if sync_names:
		prelude_lines.extend([
			'_js13k_gbc_global_values = globals().get("_js13k_gbc_global_values", None)',
			'if not isinstance(_js13k_gbc_global_values, dict):',
			'\t_js13k_gbc_global_values = {}',
			'\tglobals()["_js13k_gbc_global_values"] = _js13k_gbc_global_values',
		])
		for n in sync_names:
			prelude_lines.extend([
				'if "' + n + '" not in globals():',
				'\t' + n + ' = _js13k_gbc_global_values.get("' + n + '", 0)',
			])
	suffix_lines = []
	for n in sync_names:
		suffix_lines.append('_js13k_gbc_global_values["' + n + '"] = ' + n)
	new_code = '\n'.join(prelude_lines + [code_txt] + suffix_lines)
	return new_code, len(prelude_lines)

def TryChangeToInt (f : float):
	if int(f) == f:
		return int(f)
	else:
		return f

def Multiply (v : list, multiply : list):
	output = []
	for i, elmt in enumerate(v):
		output.append(elmt * multiply[i])
	return output

def Divide (v : list, divide : list):
	output = []
	for i, elmt in enumerate(v):
		output.append(elmt / divide[i])
	return output

def Subtract (v : list, subtract : list):
	output = []
	for i, elmt in enumerate(v):
		output.append(elmt - subtract[i])
	return output

def Round (v : list):
	output = []
	for elmt in v:
		output.append(int(round(elmt)))
	return output

def ClampComponents (v : list, min : list, max : list):
	output = []
	for i, elmt in enumerate(v):
		output.append(Clamp(elmt, min[i], max[i]))
	return output

def Rotate90 (v : Vector, clockwise : bool = True):
	if clockwise:
		return Vector((v.y, -v.x))
	else:
		return Vector((-v.y, v.x))

def GetMinComponents (v : Vector, v2 : Vector, use2D : bool = False):
	if use2D:
		return Vector((min(v.x, v2.x), min(v.y, v2.y)))
	else:
		return Vector((min(v.x, v2.x), min(v.y, v2.y), min(v.z, v2.z)))

def GetMaxComponents (v : Vector, v2 : Vector, use2D : bool = False):
	if use2D:
		return Vector((max(v.x, v2.x), max(v.y, v2.y)))
	else:
		return Vector((max(v.x, v2.x), max(v.y, v2.y), max(v.z, v2.z)))

def GetRectMinMax (ob):
	bounds = [(ob.matrix_world @ Vector(corner)) for corner in ob.bound_box]
	minX = min(v.x for v in bounds)
	minY = min(v.y for v in bounds)
	maxX = max(v.x for v in bounds)
	maxY = max(v.y for v in bounds)
	_min = Vector((minX, minY))
	_max = Vector((maxX, maxY))
	return _min, _max

def IndexOfValue (o, d : dict):
	for i, value in enumerate(d.values()):
		if o == value:
			return i
	return -1

def Copy (ob, copyData = True, copyActions = True, collection = None):
	copy = ob.copy()
	if copyData:
		copy.data = copy.data.copy()
	if copyActions and copy.animation_data:
		copy.animation_data.action = copy.animation_data.action.copy()
	if not collection:
		collection = bpy.context.collection
	collection.objects.link(copy)
	for child in ob.children:
		childCopy = Copy(child, copyData, copyActions, collection)
		childCopy.parent = copy
	return copy

def ToByteString (n, delimeters = '\\`', escapeQuotes : bool = False):
	n = round(n)
	if n < 32:
		n = 32
	byteStr = chr(n)
	if byteStr in delimeters:
		byteStr = chr(n + 1)
	elif escapeQuotes and byteStr in '"' + "'":
		byteStr = '\\' + byteStr
	return byteStr

def ToSvgNumberString (n):
	return str(TryChangeToInt(n))

def GetSvgPathFromValues (pathVals, cyclic):
	if len(pathVals) < 2:
		return ''
	output = 'M ' + ToSvgNumberString(pathVals[0]) + ',' + ToSvgNumberString(pathVals[1]) + ' '
	i = 2
	while i < len(pathVals):
		if (i - 2) % 6 == 0 and i + 6 <= len(pathVals):
			output += 'C '
			output += ToSvgNumberString(pathVals[i]) + ',' + ToSvgNumberString(pathVals[i + 1]) + ' '
			output += ToSvgNumberString(pathVals[i + 2]) + ',' + ToSvgNumberString(pathVals[i + 3]) + ' '
			output += ToSvgNumberString(pathVals[i + 4]) + ',' + ToSvgNumberString(pathVals[i + 5]) + ' '
			i += 6
		elif i + 2 <= len(pathVals):
			output += 'L ' + ToSvgNumberString(pathVals[i]) + ',' + ToSvgNumberString(pathVals[i + 1]) + ' '
			i += 2
		else:
			break
	if cyclic:
		output += 'Z'
	return output

def ToVector2String (prop : bpy.props.FloatVectorProperty):
	return '{x : ' + str(prop[0]) + ', y : ' + str(-prop[1]) + '}'

def GetFileName (filePath : str):
	filePath = filePath.replace('\\', '/')
	return filePath[filePath.rfind('/') + 1 :]

def GetVarNameForObject (ob):
	output = '_' + ob.name
	disallowedChars = ' /\\`~?|!@#$%^&*()[]{}<>=+-;:",.' + "'"
	for disallowedChar in disallowedChars:
		output = output.replace(disallowedChar, '')
	return output

def GetColor (clr : list):
	_clr = ClampComponents(Round(Multiply(clr, [255, 255, 255, 255])), [0, 0, 0, 0], [255, 255, 255, 255])
	idxOfClr = IndexOfValue(_clr, clrs)
	keyOfClr = ''
	if idxOfClr == -1:
		keyOfClr = string.ascii_letters[len(clrs)]
		clrs[keyOfClr] = _clr
	else:
		keyOfClr = string.ascii_letters[idxOfClr]
	return keyOfClr

def GetObjectPosition (ob):
	world = bpy.data.worlds[0]
	SCALE = world.exportScale
	off = Vector(world.exportOff)
	x, y, z = ob.location * SCALE
	if ob.type == 'LIGHT':
		radius = ob.data.shadow_soft_size
		x -= radius
		y -= radius
	else:
		y = -y
	x += off.x
	y += off.y
	return Round(Vector((x, y)))

