		'        pass\n'
		'if (sim is not None) and hasattr(sim, "get_rigid_body_position") and not getattr(sim, "_js13k_gbc_get_rbpos_safe", False):\n'
		'    _js13k_gbc_orig_get_rigid_body_position = sim.get_rigid_body_position\n'
