	def _replace_runtime_expr_placeholders (_text):
		src = str(_text)
		src_lower = src.lower()
		out = []
		i = 0
		while True:
			start = src_lower.find('<expr:', i)
			if start < 0:
				out.append(src[i:])
				break
			out.append(src[i:start])
			j = start + len('<expr:')
			k = j
			paren_depth = 0
			bracket_depth = 0
			brace_depth = 0
			in_quote = None
			escape = False
			close_idx = -1
			while k < len(src):
				ch = src[k]
				if in_quote is not None:
					if escape:
						escape = False
					elif ch == '\\':
						escape = True
					elif ch == in_quote:
						in_quote = None
				else:
					if ch == "'" or ch == '"':
						in_quote = ch
					elif ch == '(':
						paren_depth += 1
					elif ch == ')' and paren_depth > 0:
						paren_depth -= 1
					elif ch == '[':
						bracket_depth += 1
					elif ch == ']' and bracket_depth > 0:
						bracket_depth -= 1
					elif ch == '{':
						brace_depth += 1
					elif ch == '}' and brace_depth > 0:
						brace_depth -= 1
					elif ch == '>' and paren_depth == 0 and bracket_depth == 0 and brace_depth == 0:
						close_idx = k
						break
				k += 1
			if close_idx < 0:
				# Leave unmatched placeholder text intact for strict-mode error handling.
				out.append(src[start:])
				break
			expr = src[j:close_idx].strip()
			out.append(_eval_expr_text(expr))
			i = close_idx + 1
