	proj_x_addr = 0xC122
	proj_y_addr = 0xC123
	proj_x_hi_addr = 0xC124
	proj_y_hi_addr = 0xC125
	x_subacc_addr = 0xC11B
	y_subacc_addr = 0xC11C
