						+ ',vy0=' + str(int(_vy_before_jump))
						+ ',vy1=' + str(int(_vy_after_jump))
						+ ',gacc0=' + str(int(_gacc_y_before_jump))
						+ ',gacc1=' + str(int(_gacc_y_after_jump))
						+ ',scriptVy0=' + str(int(_script_vy_before))
